<div class="d-flex justify-content-between align-items-center mb-3 mobile-stack"><div><h1 class="page-title h3 mb-1">Riwayat Perubahan Penjualan</h1><div class="text-muted">Audit log ini membantu owner dan admin memantau create, update, pembayaran piutang, dan delete.</div></div><a class="btn btn-outline-secondary" href="<?= e(url('index.php?page=penjualan')) ?>">Kembali ke Penjualan</a></div><div class="card enterprise-card mb-3"><div class="card-body"><form class="filter-grid" method="get"><input type="hidden" name="page" value="penjualan-history"><div><label class="form-label">Cari cepat</label><input class="form-control" name="q" value="<?= e($filters['q'] ?? '') ?>" placeholder="Aktivitas, petugas, keterangan"></div><div><label class="form-label">Dari tanggal</label><input type="date" class="form-control" name="date_from" value="<?= e($filters['date_from'] ?? '') ?>"></div><div><label class="form-label">Sampai tanggal</label><input type="date" class="form-control" name="date_to" value="<?= e($filters['date_to'] ?? '') ?>"></div><div class="d-flex align-items-end gap-2"><button class="btn btn-dark flex-fill">Filter</button><a class="btn btn-outline-secondary" href="<?= e(url('index.php?page=penjualan-history')) ?>">Reset</a></div></form></div></div><div class="card enterprise-card"><div class="card-body p-0"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>No</th><th>Waktu</th><th>Ref</th><th>Aktivitas</th><th>Petugas</th><th>Keterangan</th></tr></thead><tbody><?php if (!$rows): ?><tr><td colspan="6" class="text-center text-muted py-5">Belum ada riwayat untuk filter yang dipilih.</td></tr><?php endif; ?><?php foreach ($rows as $i => $log): ?><tr><td><?= $i + 1 ?></td><td><?= e(date('d-m-Y H:i', strtotime($log['created_at']))) ?></td><td><?php if (!empty($log['data_ref_id'])): ?><a href="<?= e(url('index.php?page=penjualan-show&id='.$log['data_ref_id'])) ?>">#<?= (int)$log['data_ref_id'] ?></a><?php else: ?>-<?php endif; ?></td><td><span class="badge text-bg-light"><?= e($log['aktivitas']) ?></span></td><td><?= e($log['user_nama']) ?></td><td class="small" style="white-space:pre-line"><?= e($log['keterangan']) ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>